def gen(rng, size):
    n = max(1, min(size, 100))
    alphabet = 'abc'
    def rand_word():
        L = rng.randint(1, 6)
        return ''.join(rng.choice(alphabet) for _ in range(L))
    words = [rand_word() for _ in range(n)]
    if rng.random() < 0.7:
        target = rng.choice(words)
    else:
        target = rand_word()
    start_index = rng.randint(0, n - 1)
    return [words, target, start_index]

