class Solution:
    def closestTarget(self, words, target, startIndex):
        n = len(words)
        if words[startIndex] == target:
            return 0
        for d in range(1, n):
            if words[(startIndex + d) % n] == target or words[(startIndex - d) % n] == target:
                return d
        return -1

