class Solution:
    def closestTarget(self, words, target, startIndex):
        n = len(words)
        best = -1
        for i, w in enumerate(words):
            if w == target:
                d = abs(i - startIndex)
                d = min(d, n - d)
                if best == -1 or d < best:
                    best = d
        return best

