var closestTarget = function(words, target, startIndex) {
    const n = words.length;
    let best = -1;
    for (let i = 0; i < n; i++) {
        if (words[i] === target) {
            let d = Math.abs(i - startIndex);
            d = Math.min(d, n - d);
            if (best === -1 || d < best) best = d;
        }
    }
    return best;
};
